const fs = require("fs")
const path = require("path")

const ROOT = process.cwd()

const DRY_RUN = !process.argv.includes("--apply")

const IGNORE_DIRS = new Set([
  "node_modules",
  ".git",
  ".medusa",
  "dist",
  "build",
  ".next",
  ".turbo",
  "coverage",
  ".yalc",

  // Reports and backups generated by this tool
  "dev-kernel/reports",
  "dev-kernel/backups",

  // Generated restore points and recovery archives
  ".premium-recovery",
  "apps/backend/.premium-recovery",
  "apps\\backend\\.premium-recovery"
])

const TARGET_EXTENSIONS = new Set([
  ".js",
  ".ts",
  ".tsx",
  ".json",
  ".md",
  ".txt",
  ".yml",
  ".yaml",
  ".ps1",
  ".bat",
  ".cmd",
  ".sh"
])

const rewriteRules = [
  {
    name: "Replace hardcoded project root with ${workspaceFolder}",
    from: /C:\\Users\\H\.M\\my-medusa-store/gi,
    to: "${workspaceFolder}"
  },
  {
    name: "Replace uppercase hardcoded project root with ${workspaceFolder}",
    from: /C:\\USERS\\H\.M\\MY-MEDUSA-STORE/gi,
    to: "${workspaceFolder}"
  },
  {
    name: "Replace old root slash variant with ${workspaceFolder}",
    from: /C:\/Users\/H\.M\/my-medusa-store/gi,
    to: "${workspaceFolder}"
  }
]

function normalizePath(value) {
  return value.replace(/\\/g, "/")
}

function shouldIgnore(fullPath) {
  const rel = normalizePath(path.relative(ROOT, fullPath))

  for (const ignore of IGNORE_DIRS) {
    const normalizedIgnore = normalizePath(ignore)

    if (
      rel === normalizedIgnore ||
      rel.startsWith(normalizedIgnore + "/") ||
      rel.includes("/" + normalizedIgnore + "/")
    ) {
      return true
    }
  }

  return false
}

function shouldScanFile(filePath) {
  const ext = path.extname(filePath)
  return TARGET_EXTENSIONS.has(ext)
}

function walk(dir, files = []) {
  for (const entry of fs.readdirSync(dir, { withFileTypes: true })) {
    const fullPath = path.join(dir, entry.name)

    if (shouldIgnore(fullPath)) {
      continue
    }

    if (entry.isDirectory()) {
      walk(fullPath, files)
      continue
    }

    if (entry.isFile() && shouldScanFile(fullPath)) {
      files.push(fullPath)
    }
  }

  return files
}

function backupFile(filePath, backupRoot) {
  const rel = path.relative(ROOT, filePath)
  const backupPath = path.join(backupRoot, rel)

  fs.mkdirSync(path.dirname(backupPath), { recursive: true })
  fs.copyFileSync(filePath, backupPath)
}
function rewriteFile(filePath) {
  const original = fs.readFileSync(filePath, "utf8")
  let updated = original
  const appliedRules = []

  for (const rule of rewriteRules) {
    const before = updated
    updated = updated.replace(rule.from, rule.to)

    if (before !== updated) {
      appliedRules.push(rule.name)
    }
  }

  if (original === updated) {
    return null
  }

  return {
    file: path.relative(ROOT, filePath),
    appliedRules,
    original,
    updated
  }
}

function writeReports(reportDir, report) {
  fs.writeFileSync(
    path.join(reportDir, "portable-safe-rewrite-report.json"),
    JSON.stringify(report, null, 2),
    "utf8"
  )

  const md = [
    "# Portable Safe Rewrite Report",
    "",
    `Mode: \`${report.mode}\``,
    `Project Root: \`${report.projectRoot}\``,
    `Scanned Files: \`${report.scannedFiles}\``,
    `Changed Files: \`${report.changedFiles}\``,
    "",
    "## Changes",
    "",
    ...report.changes.map(change => [
      `### ${change.file}`,
      "",
      ...change.appliedRules.map(rule => `- ${rule}`),
      ""
    ].join("\n"))
  ].join("\n")

  fs.writeFileSync(
    path.join(reportDir, "portable-safe-rewrite-report.md"),
    md,
    "utf8"
  )
}

function main() {
  const files = walk(ROOT)

  const changes = files
    .map(rewriteFile)
    .filter(Boolean)

  const timestamp = new Date().toISOString().replace(/[:.]/g, "-")

  const reportDir = path.join(ROOT, "dev-kernel", "reports")
  const backupRoot = path.join(
    ROOT,
    "dev-kernel",
    "backups",
    `portable-rewrite-${timestamp}`
  )

  fs.mkdirSync(reportDir, { recursive: true })

  const report = {
    mode: DRY_RUN ? "dry-run" : "apply",
    projectRoot: ROOT,
    scannedFiles: files.length,
    changedFiles: changes.length,
    createdAt: new Date().toISOString(),
    ignoredDirs: [...IGNORE_DIRS],
    rules: rewriteRules.map(rule => rule.name),
    changes: changes.map(change => ({
      file: change.file,
      appliedRules: change.appliedRules
    }))
  }

  writeReports(reportDir, report)

  if (!DRY_RUN) {
    fs.mkdirSync(backupRoot, { recursive: true })

    for (const change of changes) {
      const fullPath = path.join(ROOT, change.file)

      backupFile(fullPath, backupRoot)
      fs.writeFileSync(fullPath, change.updated, "utf8")
    }
  }

  console.log("[PORTABLE SAFE REWRITE] Done")
  console.log(`[MODE] ${DRY_RUN ? "dry-run" : "apply"}`)
  console.log(`[SCANNED] ${files.length}`)
  console.log(`[CHANGED] ${changes.length}`)
  console.log("[REPORT] dev-kernel/reports/portable-safe-rewrite-report.md")

  if (!DRY_RUN) {
    console.log(`[BACKUP] ${backupRoot}`)
  } else {
    console.log("[NOTE] No files changed. Use --apply to rewrite.")
  }
}

main()